(window.webpackJsonp=window.webpackJsonp||[]).push([[319],{600:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {number} n\\n * @param {number[][]} connections\\n * @return {number[][]}\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> criticalConnections = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, connections</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> graph=<span class=\\"hljs-built_in\\">Array</span>(n).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span>[])\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [v,w] <span class=\\"hljs-keyword\\">of</span> connections){\\n    graph[v].push(w)\\n    graph[w].push(v)\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">let</span> low=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">let</span> dis=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">let</span> parent=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">-1</span>)\\n  <span class=\\"hljs-keyword\\">let</span> visited=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-literal\\">false</span>)\\n  <span class=\\"hljs-keyword\\">let</span> time=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;n;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(visited[i])<span class=\\"hljs-keyword\\">continue</span>\\n    dfs(i,visited,parent,low,dis)\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(graph,low,dis)</span>\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">v,visited,parent,low,dis</span>)</span>{\\n    visited[v]=<span class=\\"hljs-literal\\">true</span>\\n    time++\\n    dis[v]=time\\n    low[v]=time\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> w <span class=\\"hljs-keyword\\">of</span> graph[v]){\\n      <span class=\\"hljs-comment\\">// console.log(v,w)</span>\\n      <span class=\\"hljs-keyword\\">if</span>(!visited[w]){\\n        parent[w]=v\\n        dfs(w,visited,parent,low,dis)\\n        low[v]=<span class=\\"hljs-built_in\\">Math</span>.min(low[v],low[w])\\n        <span class=\\"hljs-keyword\\">if</span>(low[w]&gt;dis[v]){\\n          res.push([v,w])\\n        }        \\n      }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(w!==parent[v]){\\n        low[v]=<span class=\\"hljs-built_in\\">Math</span>.min(low[v],dis[w])\\n      }\\n    }\\n  }\\n \\n};\\n</code></pre>\\n"],"titleSlug":"critical-connections-in-a-network","hasThinking":false,"content":"<p>\u529b\u6263\u6570\u636e\u4e2d\u5fc3\u6709&nbsp;<code>n</code>&nbsp;\u53f0\u670d\u52a1\u5668\uff0c\u5206\u522b\u6309\u4ece&nbsp;<code>0</code>&nbsp;\u5230&nbsp;<code>n-1</code>&nbsp;\u7684\u65b9\u5f0f\u8fdb\u884c\u4e86\u7f16\u53f7\u3002</p>\\n\\n<p>\u5b83\u4eec\u4e4b\u95f4\u4ee5\u300c\u670d\u52a1\u5668\u5230\u670d\u52a1\u5668\u300d\u70b9\u5bf9\u70b9\u7684\u5f62\u5f0f\u76f8\u4e92\u8fde\u63a5\u7ec4\u6210\u4e86\u4e00\u4e2a\u5185\u90e8\u96c6\u7fa4\uff0c\u5176\u4e2d\u8fde\u63a5&nbsp;<code>connections</code> \u662f\u65e0\u5411\u7684\u3002</p>\\n\\n<p>\u4ece\u5f62\u5f0f\u4e0a\u8bb2\uff0c<code>connections[i] = [a, b]</code>&nbsp;\u8868\u793a\u670d\u52a1\u5668 <code>a</code>&nbsp;\u548c <code>b</code>&nbsp;\u4e4b\u95f4\u5f62\u6210\u8fde\u63a5\u3002\u4efb\u4f55\u670d\u52a1\u5668\u90fd\u53ef\u4ee5\u76f4\u63a5\u6216\u8005\u95f4\u63a5\u5730\u901a\u8fc7\u7f51\u7edc\u5230\u8fbe\u4efb\u4f55\u5176\u4ed6\u670d\u52a1\u5668\u3002</p>\\n\\n<p>\u300c\u5173\u952e\u8fde\u63a5\u300d\u662f\u5728\u8be5\u96c6\u7fa4\u4e2d\u7684\u91cd\u8981\u8fde\u63a5\uff0c\u4e5f\u5c31\u662f\u8bf4\uff0c\u5047\u5982\u6211\u4eec\u5c06\u5b83\u79fb\u9664\uff0c\u4fbf\u4f1a\u5bfc\u81f4\u67d0\u4e9b\u670d\u52a1\u5668\u65e0\u6cd5\u8bbf\u95ee\u5176\u4ed6\u670d\u52a1\u5668\u3002</p>\\n\\n<p>\u8bf7\u4f60\u4ee5\u4efb\u610f\u987a\u5e8f\u8fd4\u56de\u8be5\u96c6\u7fa4\u5185\u7684\u6240\u6709 \u300c\u5173\u952e\u8fde\u63a5\u300d\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/original_images/critical-connections-in-a-network.png\\" style=\\"width: 150px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 4, connections = [[0,1],[1,2],[2,0],[1,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>[[1,3]]\\n<strong>\u89e3\u91ca\uff1a</strong>[[3,1]] \u4e5f\u662f\u6b63\u786e\u7684\u3002</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n &lt;= 10^5</code></li>\\n\\t<li><code>n-1 &lt;= connections.length &lt;= 10^5</code></li>\\n\\t<li><code>connections[i][0] != connections[i][1]</code></li>\\n\\t<li>\u4e0d\u5b58\u5728\u91cd\u590d\u7684\u8fde\u63a5</li>\\n</ul>\\n"}')}}]);